function _execute(
    address account,
    bytes32 salt,
    bytes32 mode,
    bytes calldata executionCalldata
) internal virtual override returns (bytes[] memory returnData) {
    bytes32 id = hashOperation(account, salt, mode, executionCalldata);
    _validateStateBitmap(id, _encodeStateBitmap(OperationState.Ready));

    _schedules[id].executed = true;

    return super._execute(account, salt, mode, executionCalldata);
}

function _update(
    address from,
    address to,
    uint256 amount
) internal virtual override(ERC20, ERC20Freezable, ERC20Restricted) {
    // Note: We rely on the inherited _update chain (ERC20Freezable + ERC20Restricted) to enforce
    // the same restrictions that canTransfer would check. This avoids duplicate validation
    // while maintaining consistency between external queries and internal transfer logic.
    super._update(from, to, amount);
}

function _checkOperatorOrController(bool async, address controller, address operator) internal view virtual {
    require(
        !async || controller == operator || isOperator(controller, operator),
        ERC7540InvalidOperator(controller, operator)
    );
}

function _grantRole(bytes32 role, address account) internal virtual override returns (bool) {
    AccessControlEnumerableStorage storage $ = _getAccessControlEnumerableStorage();
    bool granted = super._grantRole(role, account);
    if (granted) {
        $._roleMembers[role].add(account);
    }
    return granted;
}

function _revokeRole(bytes32 role, address account) internal virtual override returns (bool) {
    AccessControlEnumerableStorage storage $ = _getAccessControlEnumerableStorage();
    bool revoked = super._revokeRole(role, account);
    if (revoked) {
        $._roleMembers[role].remove(account);
    }
    return revoked;
}

function getProposalId(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) public view virtual override(GovernorUpgradeable, GovernorSequentialProposalIdUpgradeable) returns (uint256) {
    return super.getProposalId(targets, values, calldatas, descriptionHash);
}

function getAccess(
    uint64 roleId,
    address account
) public view virtual returns (uint48 since, uint32 currentDelay, uint32 pendingDelay, uint48 effect) {
    Access storage access = _roles[roleId].members[account];

    since = access.since;
    (currentDelay, pendingDelay, effect) = access.delay.getFull();

    return (since, currentDelay, pendingDelay, effect);
}

function deploy(
    string memory contractName,
    bytes memory constructorData,
    Options memory opts
) internal returns (address) {
    if (opts.defender.useDefenderDeploy) {
        return DefenderDeploy.deploy(contractName, constructorData, opts.defender);
    } else {
        return _deploy(contractName, constructorData);
    }
}

function parseProposeUpgradeResponse(string memory stdout) internal returns (ProposeUpgradeResponse memory) {
    ProposeUpgradeResponse memory response;
    response.proposalId = _parseLine("Proposal ID: ", stdout, true);
    response.url = _parseLine("Proposal URL: ", stdout, false);
    return response;
}

function getApprovalProcess(string memory command) internal returns (ApprovalProcessResponse memory) {
    string[] memory inputs = buildGetApprovalProcessCommand(command);

    Vm.FfiResult memory result = Utils.runAsBashCommand(inputs);
    string memory stdout = string(result.stdout);

    if (result.exitCode != 0) {
        revert(string(abi.encodePacked("Failed to get approval process: ", string(result.stderr))));
    }

    return parseApprovalProcessResponse(stdout);
}

function deployUUPSProxy(
    string memory contractName,
    bytes memory initializerData,
    Options memory opts
) internal returns (address) {
    address impl = deployImplementation(contractName, opts);

    return Core.deploy("ERC1967Proxy.sol:ERC1967Proxy", abi.encode(impl, initializerData), opts);
}

function deployTransparentProxy(
    string memory contractName,
    address initialOwner,
    bytes memory initializerData
) internal returns (address) {
    Options memory opts;
    return deployTransparentProxy(contractName, initialOwner, initializerData, opts);
}

function deployBeacon(
    string memory contractName,
    address initialOwner,
    Options memory opts
) internal returns (address) {
    address impl = deployImplementation(contractName, opts);

    return Core.deploy("UpgradeableBeacon.sol:UpgradeableBeacon", abi.encode(impl, initialOwner), opts);
}
